#include <stdio.h>
#include <math.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int k;
        scanf("%d", &k);
        int n = (int)sqrt(k);
        if (n*n == k) {
            printf("%d\n", n);
            for (int i = 1; i < n; i++) {
                printf("%d %d\n", i, i+1);
            }
        } else {
            printf("%d\n", n+1);
            printf("1 2\n");
            for (int i = 2; i <= n; i++) {
                printf("1 %d\n", i+1);
            }
            for (int i = 2; i <= n; i++) {
                printf("%d %d\n", i, i+1);
            }
        }
    }
    return 0;
}

